ALTER TABLE `applications` ADD `hoursWorked` decimal(6,2);
ALTER TABLE `applications` ADD `totalWagesOwed` decimal(10,2);
ALTER TABLE `applications` ADD `payoutStatus` enum('unpaid','processing','paid','failed') DEFAULT 'unpaid';
ALTER TABLE `applications` ADD `payoutMethod` enum('stripe_bank','stripe_instant','cash_app','square');
ALTER TABLE `applications` ADD `payoutAt` bigint;
ALTER TABLE `users` ADD `bankRoutingNumber` varchar(256);
ALTER TABLE `users` ADD `bankAccountNumber` varchar(256);
ALTER TABLE `users` ADD `bankAccountType` enum('checking','savings');
ALTER TABLE `users` ADD `bankAccountName` varchar(256);
ALTER TABLE `users` ADD `contactPreference` enum('email','phone') DEFAULT 'email';
ALTER TABLE `users` ADD `phone` varchar(32);

